'use client';

import { useState } from 'react';

export default function AddToCartButton({ productCount }: { productCount: number }) {
  const [qty, setQty] = useState(1);
  return <button onClick={() => setQty((q) => q + 1)}>Add {qty} of {productCount} items</button>;
}
